"use client";

import { useEffect, useState } from "react";
import { fetchAirQuality } from "../lib/fetchAirQuality";

interface AQIData {
  aqi: number;
  dominentpol: string;
}

interface AQICardProps {
  city: string;
}

export default function AQICard({ city }: AQICardProps) {
  const [data, setData] = useState<AQIData | null>(null);

  useEffect(() => {
    fetchAirQuality(city).then(setData);
  }, [city]);

  if (!data) return <div>Loading...</div>;

  return (
    <div className="p-4 border rounded shadow-md w-64">
      <h2 className="text-xl font-bold">{city}</h2>
      <p>AQI: {data.aqi}</p>
      <p>Dominant Pollutant: {data.dominentpol}</p>
    </div>
  );
}
